-- =====================================================================
-- MIGRACIÓN: Cargar equipos desde Excel de Frecuencias
-- Ejecutar en el SQL Editor de Supabase
-- =====================================================================

-- 1. Asegurar que la tabla equipos tiene todas las columnas necesarias
ALTER TABLE public.equipos
  ADD COLUMN IF NOT EXISTS ruta TEXT,
  ADD COLUMN IF NOT EXISTS kks TEXT,
  ADD COLUMN IF NOT EXISTS ubicacion TEXT,
  ADD COLUMN IF NOT EXISTS componente TEXT,
  ADD COLUMN IF NOT EXISTS ubicacion_tecnica_propuesta TEXT,
  ADD COLUMN IF NOT EXISTS denominacion_ut TEXT,
  ADD COLUMN IF NOT EXISTS criticidad TEXT,
  ADD COLUMN IF NOT EXISTS frecuencia_nueva INTEGER;

-- 2. Vaciar equipos existentes e insertar los del Excel
TRUNCATE TABLE public.equipos RESTART IDENTITY CASCADE;

-- 3. Insertar todos los equipos del Excel (1065 filas)

-- 4. Verificar el resultado
SELECT ubicacion, COUNT(*) as total_equipos
FROM public.equipos
GROUP BY ubicacion
ORDER BY ubicacion;
